var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"저, 저게 뭐야! 괴물이다!","JPN":"あ、あれは何だ？　怪物だ！","ENG":"W-what the heck is that? It's a monster!","TWN":"那、那是什麼啊！怪物啊！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"도시 한복판에 어째서 저런 게 나타난 거지?!","JPN":"都会のど真ん中に、なぜあんなものが現れるんだ！？","ENG":"How did that thing make it all the way into the center of the city?","TWN":"市中心怎麼會有那種東西啊？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"태스크포스를 불러! 대체 어디에 있는 거야?!","JPN":"タスクフォースカンパニーを呼べ！　いったいどこにいるんだ！？","ENG":"Call the TASKFORCE company! Where the heck are they?","TWN":"快去叫特遣勢力！到底在哪裡啊？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L8_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여러분! 당황하지 말고 물러서세요!","JPN":"皆さん！　慌てないで下がってください！","ENG":"Everyone! Please stay calm and do not panic!","TWN":"各位！請不要驚慌，退後！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"다, 당신은 누구요?!","JPN":"あ、あなたは誰ですか？","ENG":"W-who are you?","TWN":"妳、妳是誰？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"경찰입니다! 저 괴물은 제가 처치할 테니 다들 안심하세요!","JPN":"警察です！　あの怪物は私が始末しますから、安心してください！","ENG":"I'm with the police. Stay calm. I'll take care of that thing!","TWN":"我是警察！我會處置那個怪物的，請各位放心吧！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"여기는 이유미 경정!","JPN":"こちらカスカベ警視！","ENG":"This is Major Lee Yumi.","TWN":"這裡是李悠美警正！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L13_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"추적중인 범죄자가 시내 방향으로 진입을 시도한다! 내가 처치하겠다!","JPN":"追跡中の犯罪者が市内に侵入しようとしている！\\n私が始末する！","ENG":"The suspect on the loose is attempting entry into downtown. I'll put her down!","TWN":"追捕中的罪犯試圖進入市區！我來處置她！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"네? 처치요?","JPN":"はい？　始末ですか？","ENG":"Huh? Put her down?","TWN":"咦？處置？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L17_1","type":"dialog","speaker":"RADIO_EXTRA_POLICE_NULL","text":{"KOREA":"무슨 소립니까? 아직 사살명령 같은 건 안 나왔는데......","JPN":"どういうことです？　まだ射殺命令は出ていないのに……","ENG":"What are you talking about? Use of lethal force hasn't been authorized yet!","TWN":"妳在說什麼？現在還沒有下達射殺命令之類的……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK"},{"id":"L22_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"겨, 경찰 언니...... 살려주세요...... 잘못했어요!!","JPN":"け、警察のお姉さん……助けてください……\\n反省しますから！！","ENG":"P-please! Please don't kill me... It won't happen again!","TWN":"警、警察姐姐……救救我吧……我錯了！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"시, 시끄러워!","JPN":"う、うるさい！","ENG":"Sh-shut up!","TWN":"吵、吵死了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그럼 처음부터 그런 약은 손을 안 댔어야지!","JPN":"だったら最初からそんな薬物に手を出さなければよかったじゃない！","ENG":"You shouldn't have resorted to that drug in the first place!","TWN":"那妳從一開始就不該碰這種藥！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"어쨌든 넌 오늘 여기서 끝이야!","JPN":"とにかく、あなたは今日ここで終わりだから！","ENG":"This is your end, here and now.","TWN":"無論如何，今天就是妳的死期了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"하, 하지만...... 그게 있으면......","JPN":"で、でも……あれさえあれば……","ENG":"But... I just...","TWN":"可、可是……有那個的話……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"오빠가 살아 돌아올 가능성이 높다고 해서......","JPN":"お兄ちゃんが生きて帰ってこられると聞いて……","ENG":"I was told that it'd help my brother return home safely...","TWN":"哥哥活過來的可能性就很高……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......뭐?","JPN":"……え？","ENG":"What?","TWN":"……什麼？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"그래서 구한 건데...... 바보같이 호기심에...... 자, 잠깐 시험해 보려고 하다가......","JPN":"それで手に入れたのに……好奇心に負けて……\\nす、少しだけ試してみようとしたら……","ENG":"That was all. Then I got curious and thought I'd test it out myself...","TWN":"所以我才想得到它……因為愚蠢的好奇心……稍微試驗了一下，結果……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"죄, 죄송해요!!","JPN":"本当にごめんなさい！！","ENG":"S-sorry!","TWN":"對、對不起！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그건...... 내가 알 바가 아니야.","JPN":"そんなこと……私とは関係ない。","ENG":"That's... That's none of my business.","TWN":"這……與我無關。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"범죄자는 다 똑같아...... 결국 자기 밖에 모르는 이기심이 남에게 피해를 주지.","JPN":"犯罪者はみんな同じ……\\n結局自分のことしか考えないし、そのわがままが人に被害を与えるの。","ENG":"Criminals are all the same. It's always your selfishness that puts other people in danger.","TWN":"每個罪犯都一樣……就只考慮到自己，結果卻害到別人。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"너처럼 책임의식 없이 힘을 다루는 멍청이들 때문에!","JPN":"あなたみたいに、責任感を持たないまま力を操るバカたちのせいで！","ENG":"It's because you morons brandish power so irresponsibly","TWN":"就因為妳這種毫無責任感、濫用力量的蠢貨！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"내 가족처럼 무고한 사람들이 희생되는 거라고!","JPN":"私の家族のような罪のない人たちが犠牲になるのよ！","ENG":"that innocent people like my family has to suffer!","TWN":"害得我家人這樣的無辜的人們犧牲！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"알아?!","JPN":"わかる！？","ENG":"You hear me?","TWN":"妳知道嗎？！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"나는...... 난......","JPN":"私は……私は……","ENG":"I... I...","TWN":"我……我……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GIRLSTUDENT_EXTRA_NULL_NULL","text":{"KOREA":"<color=#ff3636>크으으...... 크아아아아......!</color>","JPN":"<color=#ff3636>くうう……ぐああああっ！</color>","ENG":"<color=#ff3636>Argh... Grroooar!!!</color>","TWN":"<color=#ff3636>唔……唔啊啊啊啊……！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"CUTSCENE_TRAGEDY_HARD","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_29"},{"id":"L44_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"명중한 것 같습니다!","JPN":"命中したようです！","ENG":"I think it was a hit!","TWN":"好像命中了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"방심하지 마라! 상대는 카운터다. 이 정도로 죽을 리가 없어!","JPN":"油断するな！　相手はカウンターだ。この程度で死ぬわけがない！","ENG":"Keep your eyes on her! We're dealing with a Counter here. There's no way she went down that easily!","TWN":"別掉以輕心！對方是制裁者。不可能這麼輕易就死掉！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"위대한 예언자 마젤란께서 말씀하셨다!","JPN":"偉大なる預言者マジェラン様はおっしゃった！","ENG":"The great Magellan the Prophet has spoken!","TWN":"偉大的預言者麥哲倫說過了！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이번 임무에서 가장 큰 공훈을 세운 자를 신세계로 데려가 주신다고!!","JPN":"今回の任務で最も大きな功績を立てた者を、新世界に連れていってくださると！！","ENG":"He said the one to achieve the greatest feat in this mission will be allowed entrance into the new world!","TWN":"會將這次任務中功勞最大的人帶往新世界！！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"오오! 예언자님께서 날 신세계로 데려다 주신다고 약속하셨어.","JPN":"おお！　預言者様が俺を新世界に連れていってくださると約束した。","ENG":"Yes! He promised me that he would take me to the New World!","TWN":"哦哦！預言者大人與我約定好了，會將我帶去新世界。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_BLACK","text":{"KOREA":"바보야! 네가 아니라 우리 목표인 저 꼬맹이를 먼저 잡는 신자를 데려가 주시겠지.","JPN":"バカめ！　お前じゃなくて、目標のあの小娘を捕まえた信者を連れていってくださるはずだ。","ENG":"You dimwit! It'll be whoever catches the target first. Not you!","TWN":"笨蛋！才不是你，而是先抓住目標的那個小鬼，把她帶回去的信徒。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ZELOT_MAGELLAN_NULL_GREEN","text":{"KOREA":"시끄러워! 그게 바로 내가 될 테니까 어차피 상관없잖아!","JPN":"うるさい！　それが俺になるんだから、どう言ったっていいじゃないか！","ENG":"Shut up! It's the same thing! I'll be the first one to get her anyway!","TWN":"吵死了！反正我會成為那個最先抓到人的信徒，所以無所謂！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZELOT_MAGELLAN_NULL_GREEN","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZELOT_MAGELLAN_NULL_BLACK","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"오늘 우리의 곁에는 천사님께서 내려주신 마젤란의 신수가 함께 하신다!","JPN":"今日、私たちには天使様が与えてくださったマジェランの神獣が共にいらっしゃる！","ENG":"The divine beast of Magellan is by our side today!","TWN":"今天，天使大人賜予的麥哲倫神獸與我們同在！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"방해하는 것들은 경찰이든 카운터든 모조리 치워버려라!","JPN":"邪魔するものは警察でもカウンターでも、すべて片付けてしまえ！","ENG":"Cops, Counters, it doesn't matter. Whatever gets in your way, put them down!","TWN":"來礙事的傢伙，無論是警察還是制裁者，把他們全部都解決掉！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};